+      {
+        id: "browser-plugin-not-allowed",
+        severity: "warning",
+        message:
+          'Browser is configured, but plugins.allow does not include browser. Add "browser" to plugins.allow or remove the restrictive plugin allowlist.',
+      },
+    ];
+  }
+
+  return undefined;
+}
